import{c as i,Q as l,j as r,g as e,n as t}from"./chunks/framework.hhGiamYR.js";const h=JSON.parse('{"title":"出使德意志皇帝","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/machiavelli/diplomatic/lower/89-出使德意志皇帝.md","filePath":"research/machiavelli/machiavelli/diplomatic/lower/89-出使德意志皇帝.md"}'),o={name:"research/machiavelli/machiavelli/diplomatic/lower/89-出使德意志皇帝.md"};function c(s,a,n,m,d,p){return l(),r("div",null,[...a[0]||(a[0]=[e("h1",{id:"出使德意志皇帝",tabindex:"-1"},[t("出使德意志皇帝 "),e("a",{class:"header-anchor",href:"#出使德意志皇帝","aria-label":'Permalink to "出使德意志皇帝"'},"​")],-1),e("p",null,"出使德意志皇帝 敬请诸位大人多多关照，保重再会!",-1),e("p",null,"1507/1508年2月14日，博尔扎诺 我带着最大的敬意提醒诸位大人，为了能在必要时达成协议，宫廷希 望我能够得到签订协议的授权。 我原本以为西莫内已经穿过博洛尼亚，但他却在昨晚回到这里。他 说，回来的原因是到达彼得拉时，德意志人不准他通行。因为皇帝已经下 了死令，除非有他的信件为凭，否则任何人都不得从那里进入意大利。这 么做的原因，是为了防止任何人泄露他备战的情况。我派西莫内去送信 时，还没听说有这样的命令，所以没能给他提供这样的通行信件。不过， 我会尽力取得允许他通行的命令，然后让他再次出发。同时还会补充说 明，自从14日之后，这里发生的全部事情。 今天是19日，在过去的5天中，并没有发生什么需要向诸位大人报告 的事。主要是因为我们现在梅拉诺，离主干道很远，不能看到或听到任何 东西。不过，我还是从来自博尔扎诺和特伦特的人们那里得知：步兵和骑 兵不断经过特伦特；在过去的5天中，已经有超过3000名步兵经过博尔扎 诺，而且后续的士兵还有很多；还有大约500名士兵已经从这里出发。据 说，在离此处大概2天路程的兰德克，大约有3000名士兵正准备出发。如 此看来，事态显然是在加速发展。皇帝还在布里克森，不知道他是会从那 里出发，还是会取道弗留利。另一方面，我发觉，我仍然处于之前所说的 尴尬处境中。而且，这里的每个人都是如此。因为关于这场战争，没有人 能够预测结局将会如何，甚至连开始会怎么样都无从得知。因此，我派出 信使时，真希望他能直接飞到诸位大人那里。这样，我才能快点收到回 信。有了诸位大人的明确指示，我才能知道应该采取什么行动。结果却事 与愿违。最让我难过的是，我刚刚得知信使达伏拉西奥在路上遭到抢劫， 正准备回到此处。他本该为我带来诸位大人对我29日信件的回复。这样， 简直是雪上加霜。虽然，我得到诸位大人授权，可以开出总数50000达克",-1),e("p",null,"政务与外交著作 Legazioni,commissarie,scrittidi governo",-1)])])}const f=i(o,[["render",c]]);export{h as __pageData,f as default};
